toolArgs.file_text:
@* A single product card showing image, name, price, rating, stock status, and add-to-cart *@

<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image" role="img" aria-label="@Product.Name">
        @Product.Name
    </div>

    <div class="product-info">
        <h3 class="product-name">@Product.Name</h3>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <p class="product-rating" aria-label="@($"Rating: {RoundedRating} out of 5")">@RatingStars</p>

        @if (!Product.InStock)
        {
            <span class="out-of-stock-badge">Out of Stock</span>
        }

        <button class="add-to-cart-btn"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback OnSelected { get; set; }

    [Parameter]
    public EventCallback OnAddToCart { get; set; }

    private int RoundedRating => (int)Math.Round(Product.Rating);

    private string RatingStars
    {
        get
        {
            int filled = Math.Clamp(RoundedRating, 0, 5);
            return new string('★', filled) + new string('☆', 5 - filled);
        }
    }

    private async Task HandleCardClick() => await OnSelected.InvokeAsync();

    private async Task HandleAddToCart() => await OnAddToCart.InvokeAsync();
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
    gap: 1.5rem;
}

