arguments.file_text:
@page "/catalog"
@using sv_3826c06002db48f2874512d8d4c6e506.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-layout">
    <CatalogSidebar Categories="categories"
                    OnFilterApplied="HandleFilterApplied" />

    <main class="catalog-main">
        @if (isLoading)
        {
            <div class="catalog-status">
                <p>Loading products…</p>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="catalog-status error">
                <p>@errorMessage</p>
                <button class="retry-btn" @onclick="LoadProductsAsync">Retry</button>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="catalog-status">
                <p>No products found. Try adjusting your filters.</p>
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="result.TotalCount"
                            Page="currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (TotalPages > 1)
            {
                <CatalogPagination CurrentPage="currentPage"
                                   TotalPages="TotalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<string> categories = [];
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private bool isLoading = true;
    private string? errorMessage;

    /// <summary>Parent can handle product selection to navigate to a detail page.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialDataAsync();
    }

    private async Task LoadInitialDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            categories = await ProductService.GetCategoriesAsync();
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task LoadProductsAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandleSortChanged(string? newSort)
    {
        sortBy = newSort ?? "price_asc";
        currentPage = 1;
        await LoadProductsAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadProductsAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Add-to-cart logic would go here (e.g., invoke a cart service)
        return Task.CompletedTask;
    }
}

.catalog-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
}

.catalog-layout > :first-child {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    padding: 1.5rem 2rem;
    min-width: 0;
}

.catalog-status {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 4rem 2rem;
    color: #777;
    font-size: 1.1rem;
    text-align: center;
}

.catalog-status.error {
    color: #dc2626;
}

.retry-btn {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    border: 1px solid #dc2626;
    border-radius: 6px;
    background: #fff;
    color: #dc2626;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
}

.retry-btn:hover {
    background: #fee2e2;
}

