.catalog-layout {
    display: flex;
    min-height: calc(100vh - 4rem);
}

.catalog-layout > :first-child {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    padding: 1.5rem 2rem;
    min-width: 0;
}

.catalog-status {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 4rem 2rem;
    color: #777;
    font-size: 1.1rem;
    text-align: center;
}

.catalog-status.error {
    color: #dc2626;
}

.retry-btn {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    border: 1px solid #dc2626;
    border-radius: 6px;
    background: #fff;
    color: #dc2626;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
}

.retry-btn:hover {
    background: #fee2e2;
}

